<template><div class="shell"><aside class="sidebar"><div class="brand"><div class="brand-mark"><el-icon><FirstAidKit/></el-icon></div><div><small>NEUSOFT MEDICAL</small><strong>云脑智慧药房</strong></div></div><nav><p>药房工作区</p><router-link v-for="item in menus" :key="item.path" :to="item.path"><el-icon><component :is="item.icon"/></el-icon><span>{{item.label}}</span></router-link></nav><div class="side-help"><el-icon><CircleCheckFilled/></el-icon><div><strong>双人核对规范</strong><span>患者、药品、剂量、数量</span></div></div></aside><main><header><div><span class="mobile-brand">云脑智慧药房</span><h2>{{currentTitle}}</h2><p>{{today}}</p></div><div class="head-actions"><button class="notify"><el-icon><Bell/></el-icon><i></i></button><div class="staff"><span>{{auth.user?.name?.slice(0,1)||'药'}}</span><div><strong>{{auth.user?.name||'药房人员'}}</strong><small>药房工作站</small></div></div><el-dropdown @command="handleCommand"><button class="more"><el-icon><ArrowDown/></el-icon></button><template #dropdown><el-dropdown-menu><el-dropdown-item command="profile">个人中心</el-dropdown-item><el-dropdown-item command="logout" divided>退出登录</el-dropdown-item></el-dropdown-menu></template></el-dropdown></div></header><section class="page"><router-view/></section></main></div></template>
<script setup lang="ts">import{computed,onMounted}from'vue';import{useRoute,useRouter}from'vue-router';import{FirstAidKit,CircleCheckFilled,Bell,ArrowDown,DataBoard,DocumentChecked,Clock,Box,TrendCharts,User}from'@element-plus/icons-vue';import{useAuthStore}from'@/stores/auth';const route=useRoute(),router=useRouter(),auth=useAuthStore();const menus=[{path:'/dashboard',label:'药房总览',icon:DataBoard},{path:'/pending',label:'待发药队列',icon:DocumentChecked},{path:'/history',label:'发药记录',icon:Clock},{path:'/inventory',label:'库存查询',icon:Box},{path:'/forecast',label:'AI库存预测',icon:TrendCharts},{path:'/profile',label:'个人中心',icon:User}];const titles:Record<string,string>={dashboard:'药房总览',pending:'待发药队列',history:'发药记录',inventory:'库存查询',forecast:'AI库存预测',profile:'个人中心'};const currentTitle=computed(()=>titles[String(route.name||route.path.split('/').pop())]||menus.find(x=>x.path===route.path)?.label||'智慧药房');const today=new Intl.DateTimeFormat('zh-CN',{year:'numeric',month:'long',day:'numeric',weekday:'long'}).format(new Date());const handleCommand=(c:string)=>{if(c==='logout'){auth.signOut();router.replace('/login')}else router.push('/profile')};onMounted(()=>auth.loadUser())</script>
